SELECT SUM(allocation_amount) AS total_allocation
FROM expenditure_funding
WHERE fund_id = 1;

SELECT exp_usd_amt, category, expenditure_date, description
FROM expenditures
WHERE category_group = '1' AND category = '1' AND schl_year IN (
    SELECT schl_year FROM school_years WHERE is_current = 0
)
ORDER BY exp_usd_amt DESC;

SELECT SUM(variance) AS total_variance
FROM expenditures
WHERE region_code = 0 AND schl_year = 0;
